(function(){const typeData={"LEWF":{title:"LEWF",desc:"Quick description for LEWF goes here.",link:"#lewf"},"LEFW":{title:"LEFW",desc:"Quick description for LEFW goes here.",link:"#lefw"},"LWEF":{title:"LWEF",desc:"Quick description for LWEF goes here.",link:"#lwef"},"LWFE":{title:"LWFE",desc:"Quick description for LWFE goes here.",link:"#lwfe"},"LFEW":{title:"LFEW",desc:"Quick description for LFEW goes here.",link:"#lfew"},"LFWE":{title:"LFWE",desc:"Quick description for LFWE goes here.",link:"#lfwe"},"ELWF":{title:"ELWF",desc:"Quick description for ELWF goes here.",link:"#elwf"},"ELFW":{title:"ELFW",desc:"Quick description for ELFW goes here.",link:"#elfw"},"EWLF":{title:"EWLF",desc:"Quick description for EWLF goes here.",link:"#ewlf"},"EWFL":{title:"EWFL",desc:"Quick description for EWFL goes here.",link:"#ewfl"},"EFLW":{title:"EFLW",desc:"Quick description for EFLW goes here.",link:"#eflw"},"EFWL":{title:"EFWL",desc:"Quick description for EFWL goes here.",link:"#efwl"},"WLEF":{title:"WLEF",desc:"Quick description for WLEF goes here.",link:"#wlef"},"WLFE":{title:"WLFE",desc:"Quick description for WLFE goes here.",link:"#wlfe"},"WELF":{title:"WELF",desc:"Quick description for WELF goes here.",link:"#welf"},"WEFL":{title:"WEFL",desc:"Quick description for WEFL goes here.",link:"#wefl"},"WFLE":{title:"WFLE",desc:"Quick description for WFLE goes here.",link:"#wfle"},"WFEL":{title:"WFEL",desc:"Quick description for WFEL goes here.",link:"#wfel"},"FLEW":{title:"FLEW",desc:"Quick description for FLEW goes here.",link:"#flew"},"FLWE":{title:"FLWE",desc:"Quick description for FLWE goes here.",link:"#flwe"},"FELW":{title:"FELW",desc:"Quick description for FELW goes here.",link:"#felw"},"FEWL":{title:"FEWL",desc:"Quick description for FEWL goes here.",link:"#fewl"},"FWLE":{title:"FWLE",desc:"Quick description for FWLE goes here.",link:"#fwle"},"FWEL":{title:"FWEL",desc:"Quick description for FWEL goes here.",link:"#fwel"}};const b=document.getElementById("psyTypeBuilder"),letters=b.querySelectorAll(".psy-letter"),slots=b.querySelectorAll(".psy-slot"),result=document.getElementById("psyResult"),resultTitle=document.getElementById("psyResultTitle"),resultDesc=document.getElementById("psyResultDesc"),resetButton=document.getElementById("psyReset");let draggedLetter=null,revealTimer=null;letters.forEach(l=>{l.addEventListener("dragstart",()=>{if(!l.classList.contains("used"))draggedLetter=l});l.addEventListener("dragend",()=>{draggedLetter=null;slots.forEach(s=>s.classList.remove("drag-over"))})});slots.forEach(s=>{s.addEventListener("dragover",e=>{e.preventDefault();if(draggedLetter)s.classList.add("drag-over")});s.addEventListener("dragleave",()=>s.classList.remove("drag-over"));s.addEventListener("drop",()=>{if(!draggedLetter)return;if(s.classList.contains("filled"))releaseLetter(s.dataset.letter);fillSlot(s,draggedLetter.dataset.letter,draggedLetter.dataset.color);draggedLetter.classList.add("used");draggedLetter=null;updateResult()});s.addEventListener("click",()=>{if(s.classList.contains("filled")){releaseLetter(s.dataset.letter);resetSlot(s);updateResult()}})});function fillSlot(s,l,c){s.className=`psy-slot filled slot-${c} accept-pulse`;s.dataset.letter=l;s.dataset.color=c;s.querySelector(".slot-letter").innerText=l;setTimeout(()=>s.classList.remove("accept-pulse"),360)}function releaseLetter(v){const l=b.querySelector(`.psy-letter[data-letter="${v}"]`);if(l)l.classList.remove("used")}function resetSlot(s){s.className="psy-slot";s.querySelector(".slot-letter").innerText="";delete s.dataset.letter;delete s.dataset.color}function updateResult(){clearTimeout(revealTimer);result.classList.remove("show","result-blue","result-red","result-yellow","result-green");const filled=[...slots].filter(s=>s.classList.contains("filled"));if(filled.length<4){result.style.display="none";resetButton.classList.remove("show");return}runReadingCeremony()}function runReadingCeremony(){slots.forEach((s,i)=>{setTimeout(()=>{s.classList.add("reading");setTimeout(()=>s.classList.remove("reading"),500)},i*170)});revealTimer=setTimeout(showResult,760)}function showResult(){const code=[...slots].map(s=>s.dataset.letter).join(""),data=typeData[code],firstColor=slots[0].dataset.color;if(data){typeTitle(data.title);resultDesc.innerText=data.desc;result.href=data.link}else{typeTitle(code);resultDesc.innerText="This combination has not been added yet.";result.href="#"}result.classList.add(`result-${firstColor}`);result.style.display="block";requestAnimationFrame(()=>{result.classList.add("show");resetButton.classList.add("show")})}function typeTitle(t){resultTitle.innerHTML="";t.split("").forEach((ch,i)=>{const sp=document.createElement("span");sp.innerText=ch;sp.style.animationDelay=`${i*70}ms`;resultTitle.appendChild(sp)})}resetButton.addEventListener("click",()=>{clearTimeout(revealTimer);slots.forEach(s=>resetSlot(s));letters.forEach(l=>l.classList.remove("used"));result.classList.remove("show","result-blue","result-red","result-yellow","result-green");result.style.display="none";resetButton.classList.remove("show")})})();